INSERT IGNORE INTO daily_reports (id, user_id, title, content, submission_date, start_time, end_time, created_at, updated_at) VALUES
(1,  1, '日報管理システムの要件整理', '本日は日報管理システムの要件をチームと確認した。機能一覧と優先度を整理し、スプリント計画に落とし込んだ。', '2026-01-06', '09:00:00', '18:00:00', '2026-01-06 18:00:00', '2026-01-06 18:00:00'),
(2,  1, 'ログイン機能の実装', 'Spring Securityを用いてログイン・ログアウト機能を実装した。BCryptによるパスワードハッシュ化も合わせて対応した。', '2026-01-07', '09:00:00', '18:30:00', '2026-01-07 18:30:00', '2026-01-07 18:30:00'),
(3,  1, 'ユーザー登録機能の実装', 'ユーザー登録フォームとバリデーションを実装した。メールアドレスの重複チェックも追加した。', '2026-01-08', '09:30:00', '18:00:00', '2026-01-08 18:00:00', '2026-01-08 18:00:00'),
(4,  1, '日報作成機能の実装', '日報の新規作成フォームを実装した。タイトル・内容・提出日・勤務時間の入力項目を設けた。', '2026-01-09', '09:00:00', '19:00:00', '2026-01-09 19:00:00', '2026-01-09 19:00:00'),
(5,  1, '日報一覧表示の実装', 'Thymeleafを使って日報一覧画面を実装した。提出日の降順で表示されるよう並び替えも設定した。', '2026-01-12', '09:00:00', '18:00:00', '2026-01-12 18:00:00', '2026-01-12 18:00:00'),
(6,  1, '日報詳細表示の実装', '日報の詳細ページを実装した。コメント一覧も合わせて表示できるよう対応した。', '2026-01-13', '09:00:00', '18:00:00', '2026-01-13 18:00:00', '2026-01-13 18:00:00'),
(7,  1, '日報編集機能の実装', '自分の日報のみ編集できる機能を実装した。権限チェックをService層で行うよう設計した。', '2026-01-14', '09:00:00', '18:30:00', '2026-01-14 18:30:00', '2026-01-14 18:30:00'),
(8,  1, '日報削除機能の実装', '日報の削除機能を実装した。削除前に確認ダイアログを表示するようJavaScriptで対応した。', '2026-01-15', '09:00:00', '18:00:00', '2026-01-15 18:00:00', '2026-01-15 18:00:00'),
(9,  1, 'コメント機能の実装', '日報に対してコメントを投稿できる機能を実装した。CommentServiceを新たに作成し、ロジックを分離した。', '2026-01-16', '09:00:00', '19:00:00', '2026-01-16 19:00:00', '2026-01-16 19:00:00'),
(10, 1, 'コードレビュー対応', 'チームメンバーからのレビューコメントをもとに修正を行った。変数名の見直しとメソッドの分割を実施した。', '2026-01-19', '09:00:00', '18:00:00', '2026-01-19 18:00:00', '2026-01-19 18:00:00'),
(11, 1, 'Spring Securityの権限設定', 'ADMINロールとUSERロールで表示内容を切り替える実装を行った。sec:authorizeを活用した。', '2026-01-20', '09:30:00', '18:30:00', '2026-01-20 18:30:00', '2026-01-20 18:30:00'),
(12, 1, 'プロフィール表示機能の実装', 'ログインユーザーの情報をプロフィールページで表示できるよう実装した。', '2026-01-21', '09:00:00', '18:00:00', '2026-01-21 18:00:00', '2026-01-21 18:00:00'),
(13, 1, 'プロフィール編集機能の実装', '氏名・住所・郵便番号の編集機能を実装した。バリデーションエラー時の表示も確認した。', '2026-01-22', '09:00:00', '18:00:00', '2026-01-22 18:00:00', '2026-01-22 18:00:00'),
(14, 1, 'バグ修正：日報の更新日時が反映されない', '日報更新時にupdated_atが変わらないバグを修正した。ServiceのupdateメソッドでsetUpdatedAtを追加した。', '2026-01-23', '09:00:00', '18:00:00', '2026-01-23 18:00:00', '2026-01-23 18:00:00'),
(15, 1, 'REST APIの設計と実装', '日報一覧をJSON形式で返すREST APIを実装した。@RestControllerとReportServiceを活用した。', '2026-01-26', '09:00:00', '19:00:00', '2026-01-26 19:00:00', '2026-01-26 19:00:00'),
(16, 1, 'jQuery連携の実装', '静的HTMLページからjQueryでAPIを呼び出し、日報一覧を動的表示する機能を実装した。', '2026-01-27', '09:00:00', '18:30:00', '2026-01-27 18:30:00', '2026-01-27 18:30:00'),
(17, 1, '循環参照の調査と修正', 'JSONシリアライズ時の循環参照エラーを調査した。@JsonIgnoreをエンティティに追加して解消した。', '2026-01-28', '09:00:00', '18:00:00', '2026-01-28 18:00:00', '2026-01-28 18:00:00'),
(18, 1, 'エラーハンドリングの実装', '404・500エラーページを作成し、GlobalExceptionHandlerで一括管理する設計を実装した。', '2026-02-03', '09:00:00', '18:30:00', '2026-02-03 18:30:00', '2026-02-03 18:30:00'),
(19, 1, 'カスタム例外クラスの作成', 'ResourceNotFoundExceptionを作成し、ServiceのfindById()でorElseThrowを使うよう修正した。', '2026-02-04', '09:00:00', '18:00:00', '2026-02-04 18:00:00', '2026-02-04 18:00:00'),
(20, 1, 'ページネーション機能の実装', 'Spring Data JPAのPageableを使って日報一覧をページング表示できるよう実装した。', '2026-02-05', '09:00:00', '19:00:00', '2026-02-05 19:00:00', '2026-02-05 19:00:00'),
(21, 1, '単体テストの作成', 'ReportServiceのfindByIdメソッドに対する単体テストをJUnitで作成した。', '2026-02-06', '09:00:00', '18:00:00', '2026-02-06 18:00:00', '2026-02-06 18:00:00'),
(22, 1, 'CSSのスタイル調整', '日報一覧・詳細ページのレイアウトを調整した。ボタンの配置とフォントサイズを修正した。', '2026-02-09', '09:00:00', '18:00:00', '2026-02-09 18:00:00', '2026-02-09 18:00:00'),
(23, 1, 'バグ修正：ページネーションのボタン表示', 'Spring Boot 3.x では hasPreviousPage() が廃止されていることを確認し、hasPrevious() に修正した。', '2026-02-10', '09:00:00', '18:00:00', '2026-02-10 18:00:00', '2026-02-10 18:00:00'),
(24, 1, 'チームミーティング・進捗共有', '週次ミーティングに参加し、実装進捗と課題をチームと共有した。次週のタスクを確認した。', '2026-02-12', '10:00:00', '17:30:00', '2026-02-12 17:30:00', '2026-02-12 17:30:00'),
(25, 1, 'AOPの調査と学習', 'Spring AOPの概念（アスペクト・ジョインポイント・アドバイス）について調査し、資料にまとめた。', '2026-02-13', '09:00:00', '18:00:00', '2026-02-13 18:00:00', '2026-02-13 18:00:00'),
(26, 1, 'ログ出力機能の調査', '@Aspectを使ったServiceメソッドへのログ出力方法を調査した。実装は次週に持ち越し。', '2026-02-16', '09:00:00', '18:00:00', '2026-02-16 18:00:00', '2026-02-16 18:00:00'),
(27, 1, 'ドキュメント作成', '実装した機能の説明ドキュメントをMarkdown形式で作成した。設計意図とAOP的概念の説明を含めた。', '2026-02-17', '09:00:00', '18:00:00', '2026-02-17 18:00:00', '2026-02-17 18:00:00'),
(28, 1, 'コードリファクタリング', 'WelcomeControllerがRepositoryを直接参照していた箇所をService経由に修正した。', '2026-02-18', '09:00:00', '18:30:00', '2026-02-18 18:30:00', '2026-02-18 18:30:00'),
(29, 1, 'セキュリティ設定の見直し', 'SecurityConfigのpermitAll設定を見直し、/errorパスを追加した。未ログイン時のエラー表示を確認した。', '2026-02-19', '09:00:00', '18:00:00', '2026-02-19 18:00:00', '2026-02-19 18:00:00'),
(30, 1, '総合テスト・動作確認', 'ログイン・日報作成・編集・削除・コメントの一連の流れを手動でテストし、問題ないことを確認した。', '2026-02-20', '09:00:00', '18:00:00', '2026-02-20 18:00:00', '2026-02-20 18:00:00'),
(31, 2, 'チーム進捗確認・タスク調整', 'メンバーの進捗を確認し、タスクの優先度を調整した。遅延リスクのある項目をフォローした。', '2026-01-07', '09:00:00', '18:00:00', '2026-01-07 18:00:00', '2026-01-07 18:00:00'),
(32, 2, 'コードレビュー実施', 'ログイン機能・ユーザー登録機能のコードレビューを実施した。命名規則とエラーハンドリングを中心に指摘した。', '2026-01-09', '09:00:00', '18:00:00', '2026-01-09 18:00:00', '2026-01-09 18:00:00'),
(33, 2, 'データベース設計レビュー', 'テーブル定義と外部キー設定をレビューした。インデックスの追加を提案し、チームで合意を取った。', '2026-01-14', '09:00:00', '17:30:00', '2026-01-14 17:30:00', '2026-01-14 17:30:00'),
(34, 2, 'Spring Security設定の確認', 'ADMINロールの権限設定を確認し、管理者専用ページへのアクセス制御が正しく動作することをテストした。', '2026-01-21', '09:00:00', '18:00:00', '2026-01-21 18:00:00', '2026-01-21 18:00:00'),
(35, 2, 'メンバーへの技術共有', 'Spring Data JPAのPageable・Page<T>の使い方についてチームに説明した。ハンズオン形式で実施した。', '2026-01-28', '10:00:00', '17:00:00', '2026-01-28 17:00:00', '2026-01-28 17:00:00'),
(36, 2, 'エラー設計方針のレビュー', 'GlobalExceptionHandlerの設計をレビューした。Exception.classの一括ハンドリングのリスクについて指摘した。', '2026-02-04', '09:00:00', '18:00:00', '2026-02-04 18:00:00', '2026-02-04 18:00:00'),
(37, 2, 'AOP研修資料レビュー', '作成された研修用Markdownドキュメントをレビューした。説明の正確性と学習順序について改善提案を行った。', '2026-02-17', '09:00:00', '17:30:00', '2026-02-17 17:30:00', '2026-02-17 17:30:00'),
(38, 1, '3月のタスク整理', '3月に実施する機能追加・リファクタリングのタスクをリストアップし、スケジュールを作成した。', '2026-03-02', '09:00:00', '18:00:00', '2026-03-02 18:00:00', '2026-03-02 18:00:00'),
(39, 1, 'バリデーションの強化', '日報フォームのバリデーションメッセージを日本語に統一した。@NotBlankのmessage属性を見直した。', '2026-03-03', '09:00:00', '18:00:00', '2026-03-03 18:00:00', '2026-03-03 18:00:00'),
(40, 1, 'Thymeleafテンプレートの整理', '各テンプレートの共通ヘッダー部分を見直し、スタイルの統一を行った。', '2026-03-04', '09:00:00', '18:00:00', '2026-03-04 18:00:00', '2026-03-04 18:00:00'),
(41, 1, 'Optional の使い方の見直し', '全Serviceクラスのoptional.get()をorElseThrow()に置き換えた。ResourceNotFoundExceptionと連携させた。', '2026-03-05', '09:00:00', '18:30:00', '2026-03-05 18:30:00', '2026-03-05 18:30:00'),
(42, 1, 'トランザクション設定の確認', '@Transactionalのreadonly設定を確認し、読み取り専用メソッドにreadOnly=trueを付与した。', '2026-03-06', '09:00:00', '18:00:00', '2026-03-06 18:00:00', '2026-03-06 18:00:00'),
(43, 1, '管理者向けユーザー管理機能の確認', 'AdminUserControllerの動作を手動テストした。ユーザー作成・削除が正常に動作することを確認した。', '2026-03-09', '09:00:00', '18:00:00', '2026-03-09 18:00:00', '2026-03-09 18:00:00'),
(44, 2, '月次レビューミーティング', '3月の開発状況をチームで振り返った。完了した機能と残タスクを整理し、4月の計画を立てた。', '2026-03-31', '10:00:00', '17:00:00', '2026-03-31 17:00:00', '2026-03-31 17:00:00'),
(45, 1, '4月のキックオフ', '新しい開発フェーズのキックオフを実施した。新機能の仕様確認と担当分けを行った。', '2026-04-01', '10:00:00', '17:00:00', '2026-04-01 17:00:00', '2026-04-01 17:00:00'),
(46, 1, 'パフォーマンス調査', 'ページ読み込み速度を計測した。N+1問題が発生している箇所を特定し、改善方針を検討した。', '2026-04-07', '09:00:00', '18:30:00', '2026-04-07 18:30:00', '2026-04-07 18:30:00'),
(47, 1, 'クエリの最適化', '日報一覧取得時にN+1問題が発生していたためJPQLで結合クエリを書き直した。', '2026-04-08', '09:00:00', '19:00:00', '2026-04-08 19:00:00', '2026-04-08 19:00:00'),
(48, 2, '新メンバーのオンボーディング支援', '4月から参加した新メンバーに開発環境のセットアップと既存コードの説明を行った。', '2026-04-09', '09:00:00', '17:00:00', '2026-04-09 17:00:00', '2026-04-09 17:00:00'),
(49, 1, '5月のタスク確認・優先順位整理', '5月に実施する機能改善のタスクを整理し、優先度順に並べた。ページネーション改善を最優先とした。', '2026-05-01', '09:00:00', '18:00:00', '2026-05-01 18:00:00', '2026-05-01 18:00:00'),
(50, 1, '本日の作業まとめ', '進行中の機能実装を継続した。ページネーションの動作確認とテストデータの投入を実施した。', '2026-05-20', '09:00:00', '18:00:00', '2026-05-20 18:00:00', '2026-05-20 18:00:00');